// Extract new data from onboarding transcript
// Then merge with existing v1 data

const transcript = $('Webhook Trigger').item.json.body.transcript;
const accountId = $('Webhook Trigger').item.json.body.accountId;
const v1Memo = JSON.parse($input.item.json.data);
const now = new Date().toISOString();

function findValue(text, ...patterns) {
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match && match[1]) return match[1].trim();
  }
  return '';
}

function findList(text, ...patterns) {
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match && match[1]) {
      return match[1].split(/[,;]/).map(s => s.trim()).filter(Boolean);
    }
  }
  return [];
}

// Extract from onboarding transcript
const newCompanyName = findValue(transcript,
  /(?:business\s*name|company\s*name|company|now\s*called)\s*(?:is|:)\s*(.+?)(?:\.|,|\n|$)/i
);
const newServices = findList(transcript,
  /(?:services?\s*(?:offered|supported|we\s*offer|include|now\s*include))\s*(?:are|:)?\s*(.+?)(?:\.\s|\n|$)/i
);
const newEmergencyDef = findList(transcript,
  /(?:emergency|emergencies)\s*(?:definition|defined\s*as|include|are|now\s*include)\s*(.+?)(?:\.\s|\n|$)/i
);

// Deep merge: onboarding overrides demo, empty fields preserved
const merged = { ...v1Memo };
if (newCompanyName) merged.company_name = newCompanyName;
if (newServices.length > 0) merged.services_supported = newServices;
if (newEmergencyDef.length > 0) merged.emergency_definition = newEmergencyDef;
merged.version = 2;
merged.updated_at = now;
merged.type = 'onboarding';

// Generate changelog
const changes = [];
const ignoreKeys = ['version', 'updated_at', 'created_at', 'type', 'questions_or_unknowns'];
for (const key of Object.keys(merged)) {
  if (ignoreKeys.includes(key)) continue;
  const oldStr = JSON.stringify(v1Memo[key]);
  const newStr = JSON.stringify(merged[key]);
  if (oldStr !== newStr) {
    changes.push({
      field: key,
      path: key,
      old_value: v1Memo[key],
      new_value: merged[key],
      change_type: v1Memo[key] ? 'updated' : 'added'
    });
  }
}

const changelog = {
  account_id: accountId,
  from_version: 1,
  to_version: 2,
  created_at: now,
  total_changes: changes.length,
  changes
};

return { json: { v2Memo: merged, changelog, accountId } };

// Generate Retell Agent Spec v2 from merged memo
const memo = $input.item.json.v2Memo;
const bizName = memo.company_name || memo.account_id;
const servicesText = memo.services_supported.length > 0 ? memo.services_supported.join(', ') : 'various services';

const systemPrompt = `You are a professional AI phone receptionist for ${bizName}. They offer ${servicesText}.

Tone: Be professional, friendly, and helpful.

IMPORTANT RULES:
- Do NOT mention internal tools, functions, or systems to the caller.
- Do NOT ask more than 3 questions in a row without providing value back.
- Only collect information needed for routing and dispatch.
- Always confirm details before ending the call.

Office Hours Flow (${memo.business_hours.days} ${memo.business_hours.start}-${memo.business_hours.end}):
1. Greet → determine purpose → collect name/number → schedule or transfer → confirm → close

After Hours Flow:
1. Inform closed → check emergency → if yes: collect info + dispatch → if no: take message → close

Transfer Protocol: Wait ${memo.call_transfer_rules.timeout_seconds}s, retry ${memo.call_transfer_rules.max_retries}x
Fallback: "${memo.call_transfer_rules.message_if_fails}"`;

const retellSpec = {
  agent_name: `${bizName} AI Receptionist`,
  account_id: memo.account_id,
  version: 2,
  created_at: new Date().toISOString(),
  voice_style: memo.tone || 'professional and friendly',
  system_prompt: systemPrompt,
  key_variables: {
    timezone: memo.business_hours.timezone,
    business_hours: `${memo.business_hours.days} ${memo.business_hours.start}-${memo.business_hours.end}`,
    office_address: memo.office_address || 'Not provided',
    emergency_routing: 'Primary on-call contact',
    services: memo.services_supported
  },
  tool_invocation_placeholders: [
    { name: 'schedule_appointment', description: 'Schedule a service appointment', parameters: {} },
    { name: 'collect_customer_info', description: 'Collect caller info', parameters: {} },
    { name: 'transfer_call', description: 'Transfer to human', parameters: {} },
    { name: 'log_emergency', description: 'Log emergency request', parameters: {} }
  ],
  call_transfer_protocol: `Wait ${memo.call_transfer_rules.timeout_seconds}s, retry ${memo.call_transfer_rules.max_retries}x`,
  fallback_protocol: 'Apologize, collect name/phone/description, assure callback',
  conversation_flow: {
    office_hours_flow: memo.office_hours_flow_summary,
    after_hours_flow: memo.after_hours_flow_summary,
    opening: `Thank you for calling ${bizName}!`,
    closing: `Thank you for calling ${bizName}. Have a great day!`,
    fallback: 'Could you please repeat that?'
  }
};

return { json: { v2Memo: memo, retellSpec, changelog: $input.item.json.changelog, accountId: memo.account_id } };
